const receivedAtMs = Date.now();

// The DCS deployment dispatch envelope (command/deploy.go): a JSON-LD
// document whose canonical content hash covers the WHOLE envelope minus
// dcs:contentHash itself.
const required = ["dcs:contractDid", "dcs:contractVersion", "dcs:correlationId", "dcs:timestamp", "dcs:contentHash", "dcs:contractDocument"];

for (const key of required) {
  if (msg.payload === undefined || msg.payload[key] === undefined) {
    msg.statusCode = 400;
    msg.headers = { "Content-Type": "application/json" };
    msg.payload = { error: `Missing field: ${key}` };
    return [msg, null];
  }
}

// Recompute the canonical content hash exactly as the sender did
// (recursively key-sorted JSON, compact, no HTML escaping — see
// hashDeploymentPayload in command/deploy.go) so a tampered or corrupted
// payload is rejected rather than blindly acknowledged.
function sortKeysDeep(value) {
  if (Array.isArray(value)) {
    return value.map(sortKeysDeep);
  }
  if (value && typeof value === "object") {
    return Object.keys(value).sort().reduce((acc, key) => {
      acc[key] = sortKeysDeep(value[key]);
      return acc;
    }, {});
  }
  return value;
}

const envelope = Object.assign({}, msg.payload);
delete envelope["dcs:contentHash"];
const canonical = JSON.stringify(sortKeysDeep(envelope));
const computedHash = "sha256:" + crypto.createHash("sha256").update(canonical).digest("hex");

if (computedHash !== msg.payload["dcs:contentHash"]) {
  msg.statusCode = 400;
  msg.headers = { "Content-Type": "application/json" };
  msg.payload = {
    error: "dcs:contentHash does not match the payload",
    expected: msg.payload["dcs:contentHash"],
    computed: computedHash
  };
  return [msg, null];
}

const activatedAt = new Date().toISOString();
const correlationId = msg.payload["dcs:correlationId"];
const contractDid = msg.payload["dcs:contractDid"];

// Everything the async callback legs need, carried on a dedicated msg
// property so the http response leg and the callback legs stay independent.
const target = {
  did: contractDid,
  correlation_id: correlationId,
  payload_hash: computedHash,
  activated_at: activatedAt,
  received_at_ms: receivedAtMs
};

const ack = {
  statusCode: 200,
  headers: { "Content-Type": "application/json" },
  payload: {
    correlation_id: correlationId,
    payload_hash: computedHash,
    activated_at: activatedAt
  },
  res: msg.res,
  req: msg.req
};

return [ack, { target: target }];

// The authoritative deployment acknowledgement (DCS-FR-SM-10/-12): the
// target posts status + execution-evidence receipt back to DCS over the
// shared-secret-protected callback endpoint.
const dcsUrl = env.get('DCS_URL') || 'http://dcs-digital-contracting-service:8991';
const secret = env.get('DEPLOYMENT_CALLBACK_SECRET') || 'bdd-deployment-callback-secret';

const t = msg.target;
msg.url = dcsUrl + '/contract/deployment/callback';
msg.method = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'X-Deployment-Callback-Secret': secret
};
msg.payload = {
  did: t.did,
  correlation_id: t.correlation_id,
  status: 'ACKNOWLEDGED',
  receipt: {
    correlation_id: t.correlation_id,
    payload_hash: t.payload_hash,
    activated_at: t.activated_at
  }
};
return msg;

// The target's own measurement (DCS-FR-CWE-09/-31): how long activation
// took from receiving the dispatch to acknowledging it — a quantity only
// the target system can observe, reported over the same callback channel.
if (msg.statusCode < 200 || msg.statusCode >= 300) {
  node.warn('deployment ack callback rejected by DCS: HTTP ' + msg.statusCode + ' ' + msg.payload);
}

const dcsUrl = env.get('DCS_URL') || 'http://dcs-digital-contracting-service:8991';
const secret = env.get('DEPLOYMENT_CALLBACK_SECRET') || 'bdd-deployment-callback-secret';

const t = msg.target;
const latencyMs = Math.max(1, Date.now() - t.received_at_ms);

msg.url = dcsUrl + '/contract/deployment/callback';
msg.method = 'POST';
msg.headers = {
  'Content-Type': 'application/json',
  'X-Deployment-Callback-Secret': secret
};
msg.payload = {
  did: t.did,
  correlation_id: t.correlation_id,
  kpi: {
    metric: 'activation_latency_ms',
    value: String(latencyMs)
  }
};
return msg;

if (msg.statusCode < 200 || msg.statusCode >= 300) {
  node.warn('deployment KPI callback rejected by DCS: HTTP ' + msg.statusCode + ' ' + msg.payload);
}
return null;
